18	package com.graphhopper.jsprit.core.algorithm;
19	
20	import com.graphhopper.jsprit.core.algorithm.SearchStrategy.DiscoveredSolution;
21	import com.graphhopper.jsprit.core.algorithm.listener.*;
22	import com.graphhopper.jsprit.core.algorithm.listener.events.*;
23	import com.graphhopper.jsprit.core.algorithm.termination.PrematureAlgorithmTermination;
24	import com.graphhopper.jsprit.core.problem.VehicleRoutingProblem;
25	import com.graphhopper.jsprit.core.problem.job.Job;
26	import com.graphhopper.jsprit.core.problem.solution.SolutionCostCalculator;
27	import com.graphhopper.jsprit.core.problem.solution.VehicleRoutingProblemSolution;
28	import com.graphhopper.jsprit.core.problem.solution.route.VehicleRoute;
29	import com.graphhopper.jsprit.core.problem.solution.route.activity.TourActivity;
30	import com.graphhopper.jsprit.core.problem.solution.spec.SolutionSpec;
31	import com.graphhopper.jsprit.core.problem.solution.spec.SolutionSpecMaterializer;
32	import com.graphhopper.jsprit.core.util.Solutions;
33	import org.slf4j.Logger;
34	import org.slf4j.LoggerFactory;
35	
36	import java.util.*;
37	
38	
39	/**
40	 * Algorithm that solves a {@link VehicleRoutingProblem}.
41	 *
42	 * @author stefan schroeder
43	 */
44	public class VehicleRoutingAlgorithm {
45	
46	    private static class TerminationManager implements PrematureAlgorithmTermination {
47	
48	        private Collection<PrematureAlgorithmTermination> terminationCriteria = new ArrayList<>();
49	
50	        void addTermination(PrematureAlgorithmTermination termination) {
51	            terminationCriteria.add(termination);
52	        }
53	
54	        @Override
55	        public boolean isPrematureBreak(DiscoveredSolution discoveredSolution) {
56	            for (PrematureAlgorithmTermination termination : terminationCriteria) {
57	                if (termination.isPrematureBreak(discoveredSolution))
58	                    return true;
59	            }
60	            return false;
61	        }
62	    }
63	
64	    private static class Counter {
65	        private final String name;
66	        private long counter = 0;
67	        private long nextCounter = 1;
68	        private static final Logger log = LoggerFactory.getLogger(Counter.class);
69	
70	        public Counter(final String name) {
71	            this.name = name;
72	        }
73	
74	        public void incCounter() {
75	            long i = ++counter;
76	            long n = nextCounter;
77	            if (i >= n) {
78	                nextCounter = n * 2;
79	                log.info(this.name + n);
80	            }
81	        }
82	
83	        public void reset() {
84	            counter = 0;
85	            nextCounter = 1;
86	        }
87	    }
88	
89	    private final static Logger logger = LoggerFactory.getLogger(VehicleRoutingAlgorithm.class);
90	
91	    private final Counter counter = new Counter("iterations ");
92	
93	    private final VehicleRoutingProblem problem;
94	
95	    private final SearchStrategyManager searchStrategyManager;
96	
97	    private final VehicleRoutingAlgorithmListeners algoListeners = new VehicleRoutingAlgorithmListeners();
98	
99	    private final Collection<AlgorithmEventListener> eventListeners = new ArrayList<>();
100	
101	    private final Collection<VehicleRoutingProblemSolution> initialSolutions;
102	
103	    private int maxIterations = 100;
104	
105	    private TerminationManager terminationManager = new TerminationManager();
106	
107	    private VehicleRoutingProblemSolution bestEver = null;
108	
109	    private final SolutionCostCalculator objectiveFunction;
110	
111	    public VehicleRoutingAlgorithm(VehicleRoutingProblem problem, SearchStrategyManager searchStrategyManager) {
112	        super();
113	        this.problem = problem;
114	        this.searchStrategyManager = searchStrategyManager;
115	        initialSolutions = new ArrayList<>();
116	        objectiveFunction = null;
117	    }
118	
119	    public VehicleRoutingAlgorithm(VehicleRoutingProblem problem, Collection<VehicleRoutingProblemSolution> initialSolutions, SearchStrategyManager searchStrategyManager) {
120	        super();
121	        this.problem = problem;
122	        this.searchStrategyManager = searchStrategyManager;
123	        this.initialSolutions = initialSolutions;
124	        objectiveFunction = null;
125	    }
126	
127	    public VehicleRoutingAlgorithm(VehicleRoutingProblem problem, SearchStrategyManager searchStrategyManager, SolutionCostCalculator objectiveFunction) {
128	        super();
129	        this.problem = problem;
130	        this.searchStrategyManager = searchStrategyManager;
131	        initialSolutions = new ArrayList<>();
132	        this.objectiveFunction = objectiveFunction;
133	    }
134	
135	  /**
136	   * Adds solution to the collection of initial solutions.
137	   *
138	   * This method may lead to errors if tour activities in the solution are different to the
139	   * ones in the VRP (including differences in indexing)
140	   *
141	   * @param solution the solution to be added
142	   */
143	  public void addInitialSolution(VehicleRoutingProblemSolution solution) {
144	        solution = VehicleRoutingProblemSolution.copyOf(solution);
145	        verifyAndAdaptSolution(solution);
146	        initialSolutions.add(solution);
147	    }
148	
149	    /**
150	     * Adds a solution spec as an initial solution.
151	     * <p>
152	     * The spec will be materialized into a solution using the VRP's vehicles and jobs.
153	     * This is the preferred way to provide an initial solution as it avoids issues
154	     * with activity indexing and object references.
155	     * <p>
156	     * Unlike locked routes set via {@code VRP.Builder.setInitialRouteSpecs()}, this
157	     * initial solution is fully optimizable - jobs can be moved between routes freely.
158	     *
159	     * @param spec the solution specification
160	     * @throws IllegalArgumentException if the spec references missing vehicles or jobs
161	     */
162	    public void addInitialSolution(SolutionSpec spec) {
163	        SolutionSpecMaterializer materializer = new SolutionSpecMaterializer(problem);
164	        VehicleRoutingProblemSolution solution = materializer.materialize(spec);
165	        addInitialSolution(solution);
166	    }
167	
168	    private void verifyAndAdaptSolution(VehicleRoutingProblemSolution solution) {
169	        Set<Job> jobsNotInSolution = new HashSet<>(problem.getJobs().values());
170	        jobsNotInSolution.removeAll(solution.getUnassignedJobs());
171	        for (VehicleRoute route : solution.getRoutes()) {
172	            jobsNotInSolution.removeAll(route.getTourActivities().getJobs());
173	            if (problem.getVehicleIndex(route.getVehicle()) == 0 || problem.getVehicleIndex(route.getVehicle()) == -1)
174	                throw new IllegalStateException("vehicle used in initial solution has no index. probably a vehicle is used that has not been added to the " +
175	                    " the VehicleRoutingProblem. only use vehicles that have already been added to the problem.");
176	            for (TourActivity act : route.getActivities()) {
177	                if (act.getIndex() == 0)
178	                    throw new IllegalStateException("act in initial solution has no index. activities are created and associated to their job in VehicleRoutingProblem\n." +
179	                        " thus if you build vehicle-routes use the jobActivityFactory from vehicle routing problem like that \n" +
180	                        " VehicleRoute.Builder.newInstance(knownVehicle).setJobActivityFactory(vrp.getJobActivityFactory).addService(..)....build() \n" +
181	                        " then the activities that are created to build the route are identical to the ones used in VehicleRoutingProblem");
182	            }
183	        }
184	        solution.getUnassignedJobs().addAll(jobsNotInSolution);
185	        solution.setCost(getObjectiveFunction().getCosts(solution));
186	    }
187	
188	    /**
189	     * Sets premature termination and overrides existing termination criteria. If existing ones should not be
190	     * overridden use <code>.addTerminationCriterion(...)</code>.
191	     *
192	     * @param prematureAlgorithmTermination the termination criterion
193	     */
194	    public void setPrematureAlgorithmTermination(PrematureAlgorithmTermination prematureAlgorithmTermination) {
195	        terminationManager = new TerminationManager();
196	        terminationManager.addTermination(prematureAlgorithmTermination);
197	    }
198	
199	    /**
200	     * Adds a termination criterion to the collection of already specified termination criteria. If one
201	     * of the termination criteria is fulfilled, the algorithm terminates prematurely.
202	     *
203	     * @param terminationCriterion the termination criterion
204	     */
205	    public void addTerminationCriterion(PrematureAlgorithmTermination terminationCriterion) {
206	        terminationManager.addTermination(terminationCriterion);
207	    }
208	
209	    /**
210	     * Gets the {@link SearchStrategyManager}.
211	     *
212	     * @return SearchStrategyManager
213	     */
214	    public SearchStrategyManager getSearchStrategyManager() {
215	        return searchStrategyManager;
216	    }
217	
218	    /**
219	     * Runs the vehicle routing algorithm and returns a number of generated solutions.
220	     * <p>
221	     * <p>The algorithm runs as long as it is specified in nuOfIterations and prematureBreak. In each iteration it selects a searchStrategy according
222	     * to searchStrategyManager and runs the strategy to improve solutions.
223	     * <p>Note that clients are allowed to observe/listen the algorithm. See {@link com.graphhopper.jsprit.core.algorithm.listener.VehicleRoutingAlgorithmListener} and its according listeners.
224	     *
225	     * @return Collection<VehicleRoutingProblemSolution> the solutions
226	     * @see {@link SearchStrategyManager}, {@link com.graphhopper.jsprit.core.algorithm.listener.VehicleRoutingAlgorithmListener}, {@link com.graphhopper.jsprit.core.algorithm.listener.AlgorithmStartsListener}, {@link com.graphhopper.jsprit.core.algorithm.listener.AlgorithmEndsListener}, {@link com.graphhopper.jsprit.core.algorithm.listener.IterationStartsListener}, {@link com.graphhopper.jsprit.core.algorithm.listener.IterationEndsListener}
227	     */
228	    public Collection<VehicleRoutingProblemSolution> searchSolutions() {
229	        logger.info("algorithm starts: [maxIterations={}]", maxIterations);
230	        double now = System.currentTimeMillis();
231	        int noIterationsThisAlgoIsRunning = maxIterations;
232	        counter.reset();
233	        Collection<VehicleRoutingProblemSolution> solutions = new ArrayList<>(initialSolutions);
234	        algorithmStarts(problem, solutions);
235	        bestEver = Solutions.bestOf(solutions);
236	        if (logger.isTraceEnabled()) log(solutions);
237	        logger.info("iterations start");
238	        for (int i = 0; i < maxIterations; i++) {
239	            int iteration = i + 1;
240	            double previousBestCost = bestEver != null ? bestEver.getCost() : Double.MAX_VALUE;
241	            iterationStarts(iteration, problem, solutions);
242	            if (hasEventListeners()) {
243	                emit(new IterationStarted(iteration, System.currentTimeMillis(), previousBestCost));
244	            }
245	            logger.debug("start iteration: {}", i);
246	            counter.incCounter();
247	            SearchStrategy strategy = searchStrategyManager.getRandomStrategy();
248	            // Emit strategy selected event before the strategy runs
249	            if (hasEventListeners()) {
250	                emit(new StrategySelected(iteration, System.currentTimeMillis(), strategy.getId()));
251	            }
252	            DiscoveredSolution discoveredSolution = strategy.run(problem, solutions);
253	
254	            // Emit strategy executed event after the strategy runs with the dynamic strategy ID
255	            if (hasEventListeners() && discoveredSolution != null) {
256	                emit(new StrategyExecuted(iteration, System.currentTimeMillis(), discoveredSolution.getStrategyId()));
257	            }
258	
259	            if (logger.isTraceEnabled()) log(discoveredSolution);
260	            double oldBestCost = bestEver != null ? bestEver.getCost() : Double.MAX_VALUE;
261	            VehicleRoutingProblemSolution oldBestSolution = bestEver; // Capture before update
262	            memorizeIfBestEver(discoveredSolution);
263	            boolean isNewBest = bestEver != null && bestEver.getCost() < oldBestCost;
264	            double newSolutionCost = discoveredSolution != null ? discoveredSolution.getSolution().getCost() : Double.MAX_VALUE;
265	            boolean accepted = discoveredSolution != null && discoveredSolution.isAccepted();
266	
267	            // Emit acceptance decision event
268	            if (hasEventListeners() && discoveredSolution != null) {
269	                double threshold = strategy.getSolutionAcceptor().getCurrentThreshold();
270	                Map<String, Double> oldBreakdown = null;
271	                Map<String, Double> newBreakdown = null;
272	                if (objectiveFunction != null) {
273	                    if (oldBestSolution != null) {
274	                        oldBreakdown = objectiveFunction.getCostBreakdown(oldBestSolution);
275	                    }
276	                    newBreakdown = objectiveFunction.getCostBreakdown(discoveredSolution.getSolution());
277	                }
278	                emit(new AcceptanceDecision(iteration, System.currentTimeMillis(), oldBestCost, newSolutionCost,
279	                        accepted, strategy.getId(), isNewBest, threshold, oldBreakdown, newBreakdown));
280	            }
281	
282	            selectedStrategy(discoveredSolution, problem, solutions);
283	            if (terminationManager.isPrematureBreak(discoveredSolution)) {
284	                logger.info("premature algorithm termination at iteration {}", iteration);
285	                noIterationsThisAlgoIsRunning = iteration;
286	                if (hasEventListeners()) {
287	                    double currentBestCost = bestEver != null ? bestEver.getCost() : Double.MAX_VALUE;
288	                    emit(new IterationCompleted(iteration, System.currentTimeMillis(), newSolutionCost, currentBestCost, accepted, strategy.getId()));
289	                }
290	                break;
291	            }
292	            if (hasEventListeners()) {
293	                double currentBestCost = bestEver != null ? bestEver.getCost() : Double.MAX_VALUE;
294	                emit(new IterationCompleted(iteration, System.currentTimeMillis(), newSolutionCost, currentBestCost, accepted, strategy.getId()));
295	            }
296	            iterationEnds(iteration, problem, solutions);
297	        }
298	        logger.info("iterations end at {} iterations", noIterationsThisAlgoIsRunning);
299	        addBestEver(solutions);
300	        algorithmEnds(problem, solutions);
301	        logger.info("took {} seconds", ((System.currentTimeMillis() - now) / 1000.0));
302	        return solutions;
303	    }
304	
305	    private void addBestEver(Collection<VehicleRoutingProblemSolution> solutions) {
306	        if (bestEver != null) solutions.add(bestEver);
307	    }
308	
309	    private void log(Collection<VehicleRoutingProblemSolution> solutions) {
310	        for (VehicleRoutingProblemSolution sol : solutions) {
311	            log(sol);
312	        }
313	    }
314	
315	    private void log(VehicleRoutingProblemSolution solution) {
316	        logger.trace("solution costs: {}", solution.getCost());
317	        for (VehicleRoute r : solution.getRoutes()) {
318	            StringBuilder b = new StringBuilder();
319	            b.append(r.getVehicle().getId()).append(" : ").append("[ ");
320	            for (TourActivity act : r.getActivities()) {
321	                if (act instanceof TourActivity.JobActivity) {
322	                    b.append(((TourActivity.JobActivity) act).getJob().getId()).append(" ");
323	                }
324	            }
325	            b.append("]");
326	            logger.trace(b.toString());
327	        }
328	        StringBuilder b = new StringBuilder();
329	        b.append("unassigned : [ ");
330	        for (Job j : solution.getUnassignedJobs()) {
331	            b.append(j.getId()).append(" ");
332	        }
333	        b.append("]");
334	        logger.trace(b.toString());
335	    }
336	
337	    private void log(DiscoveredSolution discoveredSolution) {
338	        logger.trace("discovered solution: {}", discoveredSolution);
339	        log(discoveredSolution.getSolution());
340	    }
341	
342	    private void memorizeIfBestEver(DiscoveredSolution discoveredSolution) {
343	        if (discoveredSolution == null) return;
344	        if (bestEver == null) {
345	            bestEver = discoveredSolution.getSolution();
346	        } else if (discoveredSolution.getSolution().getCost() < bestEver.getCost()) {
347	            bestEver = discoveredSolution.getSolution();
348	        }
349	    }
350	
351	    private void selectedStrategy(DiscoveredSolution discoveredSolution, VehicleRoutingProblem problem, Collection<VehicleRoutingProblemSolution> solutions) {
352	        algoListeners.selectedStrategy(discoveredSolution, problem, solutions);
353	    }
354	
355	    private void algorithmEnds(VehicleRoutingProblem problem, Collection<VehicleRoutingProblemSolution> solutions) {
356	        algoListeners.algorithmEnds(problem, solutions);
357	    }
358	
359	    public VehicleRoutingAlgorithmListeners getAlgorithmListeners() {
360	        return algoListeners;
361	    }
362	
363	    public void addListener(VehicleRoutingAlgorithmListener l) {
364	        algoListeners.addListener(l);
365	        if (l instanceof SearchStrategyListener) {
366	            searchStrategyManager.addSearchStrategyListener((SearchStrategyListener) l);
367	        }
368	        if (l instanceof SearchStrategyModuleListener) {
369	            searchStrategyManager.addSearchStrategyModuleListener((SearchStrategyModuleListener) l);
370	        }
371	    }
372	
373	    /**
374	     * Adds an event listener for receiving algorithm events.
375	     *
376	     * <p>Event listeners provide a unified way to observe all aspects of the
377	     * algorithm's execution, including iteration lifecycle, ruin/recreate phases,
378	     * and acceptance decisions.</p>
379	     *
380	     * @param listener the event listener to add
381	     */
382	    public void addEventListener(AlgorithmEventListener listener) {
383	        eventListeners.add(listener);
384	    }
385	
386	    /**
387	     * Removes an event listener.
388	     *
389	     * @param listener the event listener to remove
390	     */
391	    public void removeEventListener(AlgorithmEventListener listener) {
392	        eventListeners.remove(listener);
393	    }
394	
395	    /**
396	     * Emits an event to all registered event listeners.
397	     *
398	     * <p>This method is intended for internal use by the algorithm and its
399	     * components. It has minimal overhead when no listeners are registered.</p>
400	     *
401	     * @param event the event to emit
402	     */
403	    public void emit(AlgorithmEvent event) {
404	        if (eventListeners.isEmpty()) return;
405	        for (AlgorithmEventListener listener : eventListeners) {
406	            listener.onEvent(event);
407	        }
408	    }
409	
410	    /**
411	     * Returns whether any event listeners are registered.
412	     *
413	     * <p>This can be used to avoid creating event objects when no listeners
414	     * are registered, minimizing performance overhead.</p>
415	     *
416	     * @return true if at least one event listener is registered
417	     */
418	    public boolean hasEventListeners() {
419	        return !eventListeners.isEmpty();
420	    }
421	
422	    private void iterationEnds(int i, VehicleRoutingProblem problem, Collection<VehicleRoutingProblemSolution> solutions) {
423	        algoListeners.iterationEnds(i, problem, solutions);
424	    }
425	
426	    private void iterationStarts(int i, VehicleRoutingProblem problem, Collection<VehicleRoutingProblemSolution> solutions) {
427	        algoListeners.iterationStarts(i, problem, solutions);
428	    }
429	
430	    private void algorithmStarts(VehicleRoutingProblem problem, Collection<VehicleRoutingProblemSolution> solutions) {
431	        algoListeners.algorithmStarts(problem, this, solutions);
432	    }
433	
434	    /**
435	     * Sets max number of iterations.
436	     *
437	     * @param maxIterations max number of iteration the algorithm runs
438	     */
439	    public void setMaxIterations(int maxIterations) {
440	        this.maxIterations = maxIterations;
441	        logger.debug("set maxIterations to {}", this.maxIterations);
442	    }
443	
444	    /**
445	     * Gets max number of iterations.
446	     *
447	     * @return max number of iterations
448	     */
449	    public int getMaxIterations() {
450	        return maxIterations;
451	    }
452	
453	    public SolutionCostCalculator getObjectiveFunction(){
454	        return objectiveFunction;
455	    }
456	
457	}
